import{_ as e,o as l,c as t,ag as s}from"./chunks/framework.BZohXCq9.js";const i=JSON.parse('{"title":"Flask 学习系列 (零)","description":"","frontmatter":{"title":"Flask 学习系列 (零)","date":"2023-08-13T17:21:57.000Z","description":"","tags":[],"categories":["后端"]},"headers":[],"relativePath":"posts/Series-of-Learning-Flask-0/index.md","filePath":"posts/Series-of-Learning-Flask-0/index.md","lastUpdated":1773893360000}'),r={name:"posts/Series-of-Learning-Flask-0/index.md"};function o(h,a,d,p,k,c){return l(),t("div",null,[...a[0]||(a[0]=[s('<h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>因为工作需要，开始学习了 Flask 后端开发技术。所以开始了这个新的系列（以前的坑还没填完，又要开新坑了）。</p><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h2><p>Flask 是一个使用 Python 编写的轻量级 Web 框架，它被设计成简单、易于学习和灵活的框架，旨在帮助开发人员构建具有可扩展性的 Web 应用程序。Flask 提供了一组核心功能，使开发人员能够处理路由、视图函数、模板、表单处理以及与数据库的交互。</p><p>与其他框架相比，Flask 具有以下一些特点和优势：</p><ol><li><p>简单易用：Flask 的设计理念是简单易用，它的核心功能相对较少，可以让开发人员快速入门并开发出简洁的应用。它没有太多的约束和限制，使得开发者能够自由地选择和扩展其他库和工具。</p></li><li><p>灵活性：Flask 是一个高度灵活的框架，它允许开发人员根据需要选择所需的组件和扩展。你可以根据项目要求选择适合的数据库、模板引擎和其他扩展，从而根据具体需求进行个性化的定制。</p></li><li><p>轻量级：相对于其他大型的全功能框架，如Django，Flask 是一个轻量级框架。它不包含过多的内置功能，可以避免不必要的复杂性，同时也减少了应用程序的开销。</p></li><li><p>RESTful 支持：Flask 对于构建 RESTful API 非常友好。它提供了简单的路由和视图函数处理，可以轻松地创建符合 REST 架构风格的 API 接口。</p></li><li><p>社区支持和扩展库：Flask 拥有庞大的社区支持，有大量的扩展库可供选择。这些扩展库覆盖了从数据库集成到身份验证、缓存、表单处理等各种功能，在开发过程中提供了更多选择和便利。</p></li></ol><p>与其他框架相比，Flask 的灵活性和简洁性是它的主要特点。相比之下，全功能的框架如 Django 在提供更多内置功能和自动化工具方面更为强大，适用于构建复杂和庞大的应用程序。</p><h2 id="模板引擎" tabindex="-1">模板引擎 <a class="header-anchor" href="#模板引擎" aria-label="Permalink to &quot;模板引擎&quot;">​</a></h2><p>Flask 作为服务器渲染的框架，必不可少的需要使用模板渲染引擎。Flask 使用 Jinja2 作为默认的模板渲染引擎。</p><h2 id="支持的数据库" tabindex="-1">支持的数据库 <a class="header-anchor" href="#支持的数据库" aria-label="Permalink to &quot;支持的数据库&quot;">​</a></h2><p>Flask本身并没有内置数据库支持，但可以通过使用Python包和Flask扩展来与数据库进行交互。在Flask中，常用的数据库操作插件是Flask-SQLAlchemy。</p><p>Flask-SQLAlchemy是基于ORM（对象关系映射）的SQLAlchemy框架的Flask扩展。SQLAlchemy是一个功能强大的Python SQL工具包，支持多种数据库引擎，包括MySQL、PostgreSQL、SQLite等。</p><p>使用Flask-SQLAlchemy可以简化与数据库的交互，开发者可以通过Python对象进行数据库的增删改查操作，而无需直接编写SQL语句。此扩展还提供了数据迁移的支持，可以方便地对现有数据库进行升级和改动。</p><h2 id="生态" tabindex="-1">生态 <a class="header-anchor" href="#生态" aria-label="Permalink to &quot;生态&quot;">​</a></h2><p>因为 Flask 简单轻量的设计理念，所以需要使用各种扩展来增强框架的功能。</p><h3 id="orm" tabindex="-1">ORM <a class="header-anchor" href="#orm" aria-label="Permalink to &quot;ORM&quot;">​</a></h3><ul><li>Flask-SQLAlchemy - 一个常用的 Flask ORM 扩展是 Flask-SQLAlchemy[2]。使用 Flask-SQLAlchemy，你可以方便地在 Flask 应用程序中进行数据库操作。</li></ul><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><ul><li>Flask-Admin - 简单且可扩展的管理界面框架</li></ul><h3 id="restful-api" tabindex="-1">Restful API <a class="header-anchor" href="#restful-api" aria-label="Permalink to &quot;Restful API&quot;">​</a></h3><ul><li>Flask-RESTful - 一个常用的 Flask 扩展，使得创建 Restful API 变得更加简单。它提供了一组用于定义 API 资源和请求处理器的类和方法。通过继承 Flask-RESTful 提供的 Resource 类，可以创建独立的 API 资源，并定义与之关联的请求处理函数。使用 Flask-RESTful，可以轻松管理 API 的路由、请求验证、响应处理等。</li></ul><h2 id="知识导图" tabindex="-1">知识导图 <a class="header-anchor" href="#知识导图" aria-label="Permalink to &quot;知识导图&quot;">​</a></h2>',22)])])}const n=e(r,[["render",o]]),F=Object.freeze(Object.defineProperty({__proto__:null,__pageData:i,default:n},Symbol.toStringTag,{value:"Module"}));export{F as _,i as __pageData,n as default};
